import{_ as e,o,c as a,h as d}from"./chunks/framework.Bt9YOM9y.js";const p=JSON.parse('{"title":"Content & Writing Guidelines","description":"","frontmatter":{},"headers":[],"relativePath":"guidance/content.md","filePath":"guidance/content.md"}'),r={name:"guidance/content.md"};function i(s,t,n,l,c,h){return o(),a("div",null,[...t[0]||(t[0]=[d(`<h1 id="content-writing-guidelines" tabindex="-1">Content &amp; Writing Guidelines <a class="header-anchor" href="#content-writing-guidelines" aria-label="Permalink to &quot;Content &amp; Writing Guidelines&quot;">​</a></h1><p>Words are part of the interface. This page defines the Cobalt voice and provides concrete rules for writing UI text that is clear, consistent, and helpful.</p><hr><h2 id="voice-and-tone" tabindex="-1">Voice and tone <a class="header-anchor" href="#voice-and-tone" aria-label="Permalink to &quot;Voice and tone&quot;">​</a></h2><p>Cobalt&#39;s voice is <strong>confident, concise, and supportive</strong>. We write as a knowledgeable colleague — never condescending, never vague.</p><table tabindex="0"><thead><tr><th>Attribute</th><th>What it means</th><th>Example</th></tr></thead><tbody><tr><td>Confident</td><td>State facts directly; avoid hedging.</td><td>&quot;Your file was saved.&quot; not &quot;Your file should have been saved.&quot;</td></tr><tr><td>Concise</td><td>Use as few words as possible without losing meaning.</td><td>&quot;Delete project?&quot; not &quot;Are you sure you want to delete this project from the system?&quot;</td></tr><tr><td>Supportive</td><td>Guide the user toward success.</td><td>&quot;Enter a valid email, like <a href="mailto:name@example.com" target="_blank" rel="noreferrer">name@example.com</a>.&quot;</td></tr></tbody></table><hr><h2 id="capitalization" tabindex="-1">Capitalization <a class="header-anchor" href="#capitalization" aria-label="Permalink to &quot;Capitalization&quot;">​</a></h2><p>Use <strong>sentence case</strong> for all UI elements unless the text is a proper noun or an acronym.</p><table tabindex="0"><thead><tr><th>Element</th><th>Correct</th><th>Incorrect</th></tr></thead><tbody><tr><td>Button labels</td><td>&quot;Create account&quot;</td><td>&quot;Create Account&quot;</td></tr><tr><td>Page headings</td><td>&quot;Notification settings&quot;</td><td>&quot;Notification Settings&quot;</td></tr><tr><td>Tab labels</td><td>&quot;Billing history&quot;</td><td>&quot;Billing History&quot;</td></tr><tr><td>Tooltips</td><td>&quot;Copy to clipboard&quot;</td><td>&quot;Copy To Clipboard&quot;</td></tr></tbody></table><blockquote><p><strong>Exception:</strong> Product names (Cobalt, Cobalt Design System) and acronyms (API, URL, SSO) retain their standard casing.</p></blockquote><hr><h2 id="action-labels" tabindex="-1">Action labels <a class="header-anchor" href="#action-labels" aria-label="Permalink to &quot;Action labels&quot;">​</a></h2><p>Buttons and links that trigger an action should begin with a <strong>strong verb</strong> that describes what will happen.</p><table tabindex="0"><thead><tr><th>Context</th><th>Recommended</th><th>Avoid</th></tr></thead><tbody><tr><td>Saving data</td><td>&quot;Save changes&quot;</td><td>&quot;OK&quot; or &quot;Submit&quot;</td></tr><tr><td>Deleting a resource</td><td>&quot;Delete project&quot;</td><td>&quot;Yes&quot; or &quot;Confirm&quot;</td></tr><tr><td>Navigation</td><td>&quot;View details&quot;</td><td>&quot;Click here&quot;</td></tr><tr><td>File upload</td><td>&quot;Upload file&quot;</td><td>&quot;Browse&quot;</td></tr><tr><td>Cancelling</td><td>&quot;Cancel&quot;</td><td>&quot;Never mind&quot;</td></tr></tbody></table><p>For destructive actions, pair the verb with the noun: &quot;Delete account&quot; rather than just &quot;Delete.&quot; This removes ambiguity in confirmation dialogs.</p><hr><h2 id="error-messages" tabindex="-1">Error messages <a class="header-anchor" href="#error-messages" aria-label="Permalink to &quot;Error messages&quot;">​</a></h2><p>Effective error messages follow three rules: <strong>say what happened</strong>, <strong>explain why</strong>, and <strong>offer a next step</strong>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night github-light vp-code" tabindex="0"><code><span class="line"><span>✘  &quot;An error occurred.&quot;</span></span>
<span class="line"><span>✔  &quot;We couldn&#39;t save your changes because the session expired. Sign in again to continue.&quot;</span></span></code></pre></div><p>Guidelines for writing error messages:</p><ul><li>Be specific about the cause. Avoid generic phrases like &quot;Something went wrong.&quot;</li><li>Suggest a resolution whenever possible.</li><li>Never blame the user. Write &quot;The email format is invalid&quot; not &quot;You entered a bad email.&quot;</li><li>Keep the message under two sentences in most contexts.</li></ul><hr><h2 id="placeholder-text" tabindex="-1">Placeholder text <a class="header-anchor" href="#placeholder-text" aria-label="Permalink to &quot;Placeholder text&quot;">​</a></h2><p>Placeholder text inside form fields should show a <strong>realistic example</strong>, not an instruction.</p><table tabindex="0"><thead><tr><th>Field</th><th>Correct placeholder</th><th>Incorrect placeholder</th></tr></thead><tbody><tr><td>Email</td><td><code>name@example.com</code></td><td><code>Enter your email</code></td></tr><tr><td>Phone</td><td><code>(555) 123-4567</code></td><td><code>Type phone number</code></td></tr><tr><td>Search</td><td><code>Search by name or ID</code></td><td><code>Search...</code></td></tr></tbody></table><blockquote><p><strong>Important:</strong> Placeholders disappear on focus. Never use placeholder text as a substitute for a visible label.</p></blockquote><hr><h2 id="date-and-time-formatting" tabindex="-1">Date and time formatting <a class="header-anchor" href="#date-and-time-formatting" aria-label="Permalink to &quot;Date and time formatting&quot;">​</a></h2><p>Use the following defaults across all Cobalt applications. Allow locale overrides when the component supports it.</p><table tabindex="0"><thead><tr><th>Format</th><th>Example</th><th>Usage</th></tr></thead><tbody><tr><td>Short date</td><td><code>Mar 11, 2026</code></td><td>Tables, cards, metadata</td></tr><tr><td>Long date</td><td><code>March 11, 2026</code></td><td>Page headers, reports</td></tr><tr><td>Time (12-hour)</td><td><code>2:30 PM</code></td><td>Timestamps, schedules</td></tr><tr><td>Relative time</td><td><code>3 minutes ago</code></td><td>Activity feeds, notifications</td></tr><tr><td>Date + time</td><td><code>Mar 11, 2026, 2:30 PM</code></td><td>Logs, audit trails</td></tr></tbody></table><p>Use <code>co-date</code> and <code>co-time</code> components for automatic locale-aware formatting. Avoid hardcoding date strings.</p><hr><h2 id="number-formatting" tabindex="-1">Number formatting <a class="header-anchor" href="#number-formatting" aria-label="Permalink to &quot;Number formatting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Example</th><th>Notes</th></tr></thead><tbody><tr><td>Integers</td><td><code>1,234</code></td><td>Use locale-appropriate thousands separator.</td></tr><tr><td>Decimals</td><td><code>1,234.56</code></td><td>Default to two decimal places for currency.</td></tr><tr><td>Percentages</td><td><code>42%</code></td><td>No space before the percent sign.</td></tr><tr><td>File sizes</td><td><code>2.4 MB</code></td><td>Use binary units (KB, MB, GB).</td></tr><tr><td>Abbreviations</td><td><code>12.5K</code>, <code>3.2M</code></td><td>Use for large numbers in dashboards and charts.</td></tr></tbody></table><blockquote><p><strong>Tip:</strong> Use the <code>co-number</code> component with <code>format=&quot;currency&quot;</code> or <code>format=&quot;compact&quot;</code> to handle these rules automatically.</p></blockquote><hr><h2 id="quick-reference-checklist" tabindex="-1">Quick reference checklist <a class="header-anchor" href="#quick-reference-checklist" aria-label="Permalink to &quot;Quick reference checklist&quot;">​</a></h2><ul class="contains-task-list"><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Sentence case everywhere (except proper nouns and acronyms)</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Buttons start with a verb</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Error messages explain cause and suggest a fix</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Placeholders show examples, not instructions</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> Dates and numbers use Cobalt formatting components</li></ul>`,39)])])}const m=e(r,[["render",i]]);export{p as __pageData,m as default};
